const companies = $('Get All Companies').all();
const crumb = $('Get Yahoo Crumb').first().json.data || $('Get Yahoo Crumb').first().json || '';

// Build ticker list for batch query
const tickers = companies.map(c => c.json.yahoo_ticker).join(',');

return [{ json: { tickers, crumb: typeof crumb === 'string' ? crumb : '', companies: companies.map(c => c.json) } }];

const response = $input.first().json;
const companies = $('Prepare Tickers').first().json.companies;
const quotes = response.quoteResponse?.result || [];

// Map Yahoo data to our schema
const results = [];
for (const company of companies) {
  const quote = quotes.find(q => q.symbol === company.yahoo_ticker);
  if (!quote) {
    results.push({
      json: {
        company_id: company.id,
        company_name: company.name,
        ticker: company.ticker,
        yahoo_ticker: company.yahoo_ticker,
        is_target: company.is_target,
        close_price: null,
        market_cap: null,
        volume: null,
        week_change_pct: null,
        error: 'No quote data'
      }
    });
    continue;
  }

  results.push({
    json: {
      company_id: company.id,
      company_name: company.name,
      ticker: company.ticker,
      yahoo_ticker: company.yahoo_ticker,
      is_target: company.is_target,
      close_price: quote.regularMarketPrice || null,
      market_cap: quote.marketCap || null,
      volume: quote.regularMarketVolume || null,
      week_change_pct: quote.fiftyTwoWeekChangePercent || quote.regularMarketChangePercent || null
    }
  });
}

return results;

const items = $input.all().map(i => i.json);
const allItems = $('Extract Financials').all().map(i => i.json);

const fci = allItems.find(i => i.is_target);
const peers = allItems.filter(i => !i.is_target && i.close_price).sort((a,b) => (b.market_cap || 0) - (a.market_cap || 0));

// Format helpers
const fmtPrice = (p) => p ? `$${Number(p).toFixed(2)}` : 'N/A';
const fmtCap = (c) => {
  if (!c) return 'N/A';
  if (c >= 1e9) return `$${(c/1e9).toFixed(1)}B`;
  if (c >= 1e6) return `$${(c/1e6).toFixed(1)}M`;
  return `$${Number(c).toLocaleString()}`;
};
const fmtVol = (v) => {
  if (!v) return 'N/A';
  if (v >= 1e6) return `${(v/1e6).toFixed(1)}M`;
  if (v >= 1e3) return `${(v/1e3).toFixed(0)}K`;
  return v.toString();
};
const fmtPct = (p) => p ? `${Number(p).toFixed(2)}%` : 'N/A';

const peerSummary = allItems.filter(i => i.close_price).map(i => 
  `${i.company_name} (${i.ticker}): Price ${fmtPrice(i.close_price)}, Cap ${fmtCap(i.market_cap)}, Change ${fmtPct(i.week_change_pct)}`
).join('\n');

return [{
  json: {
    fci,
    peers,
    total: allItems.length,
    peer_summary: peerSummary,
    fci_price: fmtPrice(fci?.close_price),
    fci_market_cap: fmtCap(fci?.market_cap),
    fci_volume: fmtVol(fci?.volume)
  }
}];

