const compData = $('Build Comparison').first().json;
const today = new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

let gptResponse;
try {
  const content = $('GPT-5 Mini Narrative').first().json.message.content;
  const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  gptResponse = JSON.parse(cleaned);
} catch (e) {
  gptResponse = {
    market_narrative: $('GPT-5 Mini Narrative').first().json.message.content,
    notable_movers: ''
  };
}

// Build peer table rows
const fmtPrice = (p) => p ? `$${Number(p).toFixed(2)}` : 'N/A';
const fmtCap = (c) => {
  if (!c) return 'N/A';
  if (c >= 1e9) return `$${(c/1e9).toFixed(1)}B`;
  if (c >= 1e6) return `$${(c/1e6).toFixed(1)}M`;
  return `$${Number(c).toLocaleString()}`;
};
const fmtVol = (v) => {
  if (!v) return 'N/A';
  if (v >= 1e6) return `${(v/1e6).toFixed(1)}M`;
  if (v >= 1e3) return `${(v/1e3).toFixed(0)}K`;
  return v.toString();
};

const peerRows = compData.peers.map((p, i) => {
  const bgColor = i % 2 === 0 ? '#ffffff' : '#f8f9fa';
  const changeColor = p.week_change_pct > 0 ? '#28a745' : p.week_change_pct < 0 ? '#dc3545' : '#6c757d';
  return `<tr style="background-color:${bgColor};"><td style="padding:6px 8px;border-bottom:1px solid #eee;">${p.company_name}</td><td align="center" style="padding:6px 8px;border-bottom:1px solid #eee;">${p.ticker}</td><td align="right" style="padding:6px 8px;border-bottom:1px solid #eee;">${fmtPrice(p.close_price)}</td><td align="right" style="padding:6px 8px;border-bottom:1px solid #eee;">${fmtCap(p.market_cap)}</td><td align="right" style="padding:6px 8px;border-bottom:1px solid #eee;">${fmtVol(p.volume)}</td><td align="right" style="padding:6px 8px;border-bottom:1px solid #eee;color:${changeColor};font-weight:bold;">${p.week_change_pct ? p.week_change_pct.toFixed(2) + '%' : 'N/A'}</td></tr>`;
}).join('');

let html = `<!DOCTYPE html>
<html><head><meta charset="UTF-8"></head>
<body style="margin:0;padding:0;background-color:#f4f4f4;font-family:Arial,sans-serif;">
<table width="100%" cellpadding="0" cellspacing="0" style="background-color:#f4f4f4;"><tr><td align="center" style="padding:20px 0;">
<table width="600" cellpadding="0" cellspacing="0" style="background-color:#fff;border-radius:8px;overflow:hidden;">
<tr><td style="background-color:#0d1b2a;padding:30px 40px;text-align:center;"><h1 style="color:#fff;margin:0;font-size:24px;">Weekly Financial Pulse</h1><p style="color:#a0a0c0;margin:8px 0 0;font-size:14px;">Market Close &bull; ${today}</p></td></tr>
<tr><td style="padding:30px 40px 10px;"><h2 style="color:#0d1b2a;font-size:18px;margin:0 0 15px;border-bottom:2px solid #e6e6e6;padding-bottom:10px;">FCI Spotlight</h2><table width="100%" cellpadding="0" cellspacing="0"><tr><td width="30%" align="center" style="padding:15px;background-color:#f0f7ff;border-radius:6px;"><p style="margin:0;color:#999;font-size:11px;text-transform:uppercase;">Price</p><p style="margin:5px 0 0;color:#1a1a2e;font-size:22px;font-weight:bold;">${compData.fci_price}</p></td><td width="5%"></td><td width="30%" align="center" style="padding:15px;background-color:#f0f7ff;border-radius:6px;"><p style="margin:0;color:#999;font-size:11px;text-transform:uppercase;">Market Cap</p><p style="margin:5px 0 0;color:#1a1a2e;font-size:22px;font-weight:bold;">${compData.fci_market_cap}</p></td><td width="5%"></td><td width="30%" align="center" style="padding:15px;background-color:#f0f7ff;border-radius:6px;"><p style="margin:0;color:#999;font-size:11px;text-transform:uppercase;">Volume</p><p style="margin:5px 0 0;color:#1a1a2e;font-size:22px;font-weight:bold;">${compData.fci_volume}</p></td></tr></table></td></tr>
<tr><td style="padding:20px 40px 10px;"><h2 style="color:#0d1b2a;font-size:18px;margin:0 0 15px;border-bottom:2px solid #e6e6e6;padding-bottom:10px;">Peer Comparison</h2><table width="100%" cellpadding="6" cellspacing="0" style="border-collapse:collapse;font-size:12px;"><tr style="background-color:#f8f9fa;"><th align="left" style="padding:8px;border-bottom:2px solid #dee2e6;">Company</th><th align="center" style="padding:8px;border-bottom:2px solid #dee2e6;">Ticker</th><th align="right" style="padding:8px;border-bottom:2px solid #dee2e6;">Price</th><th align="right" style="padding:8px;border-bottom:2px solid #dee2e6;">Mkt Cap</th><th align="right" style="padding:8px;border-bottom:2px solid #dee2e6;">Vol</th><th align="right" style="padding:8px;border-bottom:2px solid #dee2e6;">Wk %</th></tr>${peerRows}</table></td></tr>
<tr><td style="padding:20px 40px 10px;"><h2 style="color:#0d1b2a;font-size:18px;margin:0 0 15px;border-bottom:2px solid #e6e6e6;padding-bottom:10px;">Market Narrative</h2><p style="color:#444;font-size:14px;line-height:1.7;margin:0;">${gptResponse.market_narrative}</p></td></tr>
<tr><td style="padding:20px 40px 10px;"><h2 style="color:#0d1b2a;font-size:18px;margin:0 0 15px;border-bottom:2px solid #e6e6e6;padding-bottom:10px;">Notable Movers</h2><ul style="padding-left:20px;color:#444;font-size:14px;line-height:1.7;">${gptResponse.notable_movers}</ul></td></tr>
<tr><td style="padding:30px 40px;background-color:#f9f9f9;border-top:1px solid #e6e6e6;"><p style="color:#999;font-size:12px;margin:0;text-align:center;">FCI Competitive Intelligence Agent &bull; GPT-5 mini<br>Companies tracked: ${compData.total} &bull; Data source: Yahoo Finance</p></td></tr>
</table></td></tr></table></body></html>`;

return [{ json: { html, subject: `Weekly Financial Pulse — ${today}` } }];
